const NON_CRYPTO_PREFIXES: &[&str] = &["NCSK", "JPM", "AAPL", "TSLA", "SPX", "NDX", "GOLD", "SILVER", "OIL", "NATGAS", "EUR", "GBP", "JPY", "AUD", "CAD", "CHF", "NZD", "XAU", "XAG", "WTI", "BRENT"];
pub fn validate_crypto_perp_symbol(symbol: &str) -> Result<(), &'static str> { if !symbol.ends_with("-USDT") { return Err("símbolo não termina com -USDT"); } let base = match symbol.strip_suffix("-USDT") { Some(b) if !b.is_empty() => b, _ => return Err("base asset vazio após remover -USDT") }; if !base.chars().all(|c| c.is_ascii_alphanumeric()) { return Err("base asset contém caracteres inválidos"); } if base.len() < 2 { return Err("base asset muito curto"); } if base.len() > 10 { return Err("base asset muito longo"); } let base_upper = base.to_uppercase(); for prefix in NON_CRYPTO_PREFIXES { if base_upper.starts_with(prefix) { return Err("prefixo na blacklist"); } } let chars: Vec<char> = base.chars().collect(); let ends_with_digit = chars.last().map(|c| c.is_ascii_digit()).unwrap_or(false); let has_only_alpha_prefix = chars.iter().take(chars.len().saturating_sub(1)).all(|c| c.is_ascii_alphabetic()); if ends_with_digit && has_only_alpha_prefix && base.len() <= 6 { return Err("padrão de ticker de ação"); } Ok(()) }
pub fn filter_valid_symbols(symbols: &[String]) -> Vec<String> { symbols.iter().filter_map(|s| match validate_crypto_perp_symbol(s) { Ok(()) => Some(s.clone()), Err(_) => None }).collect() }
